  const token = at.app_access_token;
  console.log('Token OK:', token ? 'yes' : 'no');

  // Get fields
  const fieldsRes = await new Promise((resolve, reject) => {
    const options = {
      hostname: 'open.feishu.cn',
      path: \`/open-apis/bitable/v1/apps/\${appToken}/tables/\${tableId}/fields\`,
      method: 'GET',
      headers: { Authorization: \`Bearer \${token}\` }
    };
    const req = https.request(options, res => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => resolve(JSON.parse(data)));
    });
    req.on('error', reject);
    req.end();
  });
  console.log('Fields:', JSON.stringify(fieldsRes.data?.items || [], null, 2));
}

main().catch(console.error);
